import type { TagEmits, TagProps as _TagProps } from '@soybeanjs/headless/tag';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { TagShape, TagVariant } from '@/styles/tag';
import type { ThemeColor, ThemeSize } from '@/theme';

/**
 * Properties for the Tag component.
 */
export interface TagProps extends _TagProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Theme color of the component.
   */
  color?: ThemeColor;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Visual variant of the component.
   */
  variant?: TagVariant;
  /**
   * Shape of the component.
   */
  shape?: TagShape;
  /**
   * Content.
   */
  content?: string;
  /**
   * Whether the component can be closed.
   */
  closable?: boolean;
}

export type { TagEmits, TagVariant, TagShape };

// @unocss-include
import { cv } from '@soybeanjs/cva';
import type { VariantProps } from '@soybeanjs/cva';

export const tagVariants = cv({
  base: 'inline-flex items-center border font-semibold',
  variants: {
    color: {
      primary: 'border-primary text-primary',
      destructive: 'border-destructive text-destructive',
      success: 'border-success text-success',
      warning: 'border-warning text-warning',
      info: 'border-info text-info',
      carbon: 'border-carbon text-carbon',
      secondary: 'border-secondary-foreground/50 text-secondary-foreground',
      accent: 'border-accent-foreground/50 text-accent-foreground'
    },
    variant: {
      solid: '',
      pure: 'bg-background text-foreground border-border',
      outline: 'bg-background',
      soft: 'border-0',
      ghost: '',
      raw: 'bg-transparent border-0'
    },
    size: {
      xs: 'gap-0.5 h-4 px-1 text-4xs',
      sm: 'gap-0.75 h-4.5 px-1.5 text-3xs',
      md: 'gap-1 h-5 px-2 text-2xs',
      lg: 'gap-1.25 h-5.5 px-2.5 text-xs',
      xl: 'gap-1.5 h-6 px-3 text-sm',
      '2xl': 'gap-2 h-7 px-4 text-base'
    },
    shape: {
      auto: 'rounded-md',
      rounded: 'rounded-full'
    }
  },
  compoundVariants: [
    {
      color: 'primary',
      variant: 'solid',
      class: `bg-primary text-primary-foreground`
    },
    {
      color: 'destructive',
      variant: 'solid',
      class: `bg-destructive text-destructive-foreground`
    },
    {
      color: 'success',
      variant: 'solid',
      class: `bg-success text-success-foreground`
    },
    {
      color: 'warning',
      variant: 'solid',
      class: `bg-warning text-warning-foreground`
    },
    {
      color: 'info',
      variant: 'solid',
      class: `bg-info text-info-foreground`
    },
    {
      color: 'carbon',
      variant: 'solid',
      class: `bg-carbon text-carbon-foreground`
    },
    {
      color: 'secondary',
      variant: 'solid',
      class: `bg-secondary text-secondary-foreground`
    },
    {
      color: 'accent',
      variant: 'solid',
      class: `bg-accent text-accent-foreground`
    },
    {
      color: 'primary',
      variant: ['soft', 'ghost'],
      class: 'bg-primary/10'
    },
    {
      color: 'destructive',
      variant: ['soft', 'ghost'],
      class: 'bg-destructive/10'
    },
    {
      color: 'success',
      variant: ['soft', 'ghost'],
      class: 'bg-success/10'
    },
    {
      color: 'warning',
      variant: ['soft', 'ghost'],
      class: 'bg-warning/10'
    },
    {
      color: 'info',
      variant: ['soft', 'ghost'],
      class: 'bg-info/10'
    },
    {
      color: 'carbon',
      variant: ['soft', 'ghost'],
      class: 'bg-carbon/10'
    },
    {
      color: 'secondary',
      variant: ['soft', 'ghost'],
      class: 'bg-secondary-foreground/5'
    },
    {
      color: 'accent',
      variant: ['soft', 'ghost'],
      class: 'bg-accent-foreground/5'
    }
  ],
  defaultVariants: {
    color: 'primary',
    variant: 'solid',
    size: 'md',
    shape: 'auto'
  }
});

type TagVariants = VariantProps<typeof tagVariants>;

export type TagVariant = NonNullable<TagVariants['variant']>;

export type TagShape = NonNullable<TagVariants['shape']>;

import { useContext } from '@soybeanjs/headless/composables';
import type { ConfigProviderContext } from './types';

export const [provideConfigProviderContext, useConfigProvider] = useContext<ConfigProviderContext>('UiConfigProvider');

import type { IconValue } from '@soybeanjs/headless';
import type { IconProps as IconifyIconProps } from '@iconify/vue';

/**
 * Properties for the Icon component.
 */
export interface IconProps extends Omit<IconifyIconProps, 'icon'> {
  /**
   * Icon rendered by the component.
   */
  icon: IconValue;
}

export type { IconValue };

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;

import type { ConfigProviderProps as _ConfigProviderProps } from '@soybeanjs/headless/config-provider';
import type { ProgressProviderProps } from '@soybeanjs/headless/progress';
import type { PropsToContext } from '@soybeanjs/headless/types';
import type { ThemeOptions } from '@soybeanjs/shadcn-theme';
import type { ThemeSize } from '@/theme';
import type { ToastProviderProps } from '../toast/types';

export interface IconifyOptions {
  /**
   * The default width of the icon.
   *
   * @defaultValue '1.25em'
   */
  width?: string;
  /**
   * The default height of the icon.
   *
   * @defaultValue '1.25em'
   */
  height?: string;
}

/**
 * Properties for the ConfigProvider component.
 */
export interface ConfigProviderProps extends _ConfigProviderProps {
  /** The theme options. */
  theme?: ThemeOptions;
  /**
   * The size options.
   *
   * @deprecated Use `theme.size` instead.
   */
  size?: ThemeSize;
  /** The iconify options. */
  iconify?: IconifyOptions;
  /** The global top progress configuration of your application. */
  progress?: Partial<ProgressProviderProps>;
  /** The global toast configuration of your application. This will be inherited by the related components. */
  toast?: Partial<ToastProviderProps>;
  /**
   * Whether to use custom toast rendering. If set to `true`, the `ToastProvider` will not render the default toast UI, and you can import `ToastProvider` component to render custom toast UI.
   *
   * @default false
   */
  customToast?: boolean;
}

/**
 * Context for the ConfigProvider component.
 */
export interface ConfigProviderContext
  extends PropsToContext<Omit<ConfigProviderProps, 'iconRender'>>, Pick<ConfigProviderProps, 'iconRender'> {}

export type { ThemeOptions };

import type { ToastProviderProps as _ToastProviderProps, ToastUi } from '@soybeanjs/headless/toast';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the ToastProvider component.
 */
export interface ToastProviderProps extends _ToastProviderProps {
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: ToastUi;
}
